const postId = $('Google Sheets1').item.json['Post id'];
const inputString = $('Google Sheets1').item.json['Comtemt Chưa Rep'] || "";

// Tách các dòng từ cột "Comtemt Chưa Rep"
const commentLines = inputString
  .split('\n')
  .map(l => l.trim())
  .filter(Boolean);

// Ghép postId thành item đầu tiên
const result = [
  {
    json: {
      comment_status: postId
    }
  },
  ...commentLines.map(line => ({
    json: {
      comment_status: line
    }
  }))
];

return result;

// Lấy chuỗi link từ Google Sheets
const gs = $item(0).$node["Google Sheets"].json;
const text = gs["Link Shopee"];

// Tách theo xuống dòng (cả \n hoặc \r\n)
const links = text.split(/\r?\n/).map(l => l.trim()).filter(l => l !== '');

// Random 1 link trong danh sách
const randomLink = links[Math.floor(Math.random() * links.length)];

// Tạo đoạn random để tránh spam Facebook
const randomParam = Math.random().toString(36).substring(2, 8);

// Gắn UTM/tham số random vào link Shopee
const finalLink = `${randomLink}?fb=${randomParam}`;

return [
  {
    json: {
      LinkShopee: finalLink
    }
  }
];

