const data = $input.item.json.body.data;

// Nếu mảng data có ít nhất 1 reply
if (Array.isArray(data) && data.length > 0) {
    return [{ status: "ĐÃ REP COMMENT", replied: true }];
} else {
    return [{ status: "CHƯA REP COMMENT", replied: false }];
}

// items từ node trước
const items = $input.all().map(i => i.json);

// Hàm check tồn tại
function isNotExistInSheet(items) {
  if (!items) return true;

  // []
  if (items.length === 0) return true;

  // [{}]
  if (
    items.length === 1 &&
    typeof items[0] === 'object' &&
    Object.keys(items[0]).length === 0
  ) {
    return true;
  }

  return false;
}

const notExist = isNotExistInSheet(items);

return [
  {
    json: {
      notExistInSheet: notExist,
      rawItems: items
    }
  }
];

